/*
 * modff() test harness — prints (input_hex, integer_hex, fraction_hex) triples.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly modff  (test_modff_opt.elf)
 *   2. Linked with toolchain's default modff        (test_modff_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

#ifdef EN_PERF
static volatile float g_acc;

static void emit(float x)
{
    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    float ipart;
    g_acc += modff(vx, &ipart);
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}
#else
static void emit(float x)
{
    float ipart;
    float fpart = modff(x, &ipart);
    printf("%08lx %08lx %08lx\n",
           (unsigned long)f2u(x), (unsigned long)f2u(ipart),
           (unsigned long)f2u(fpart));
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}
#endif

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);
    emit(-0.0f);
    emit_u(0x7fc00000u);  /* qNaN */
    emit_u(0x7f800001u);  /* sNaN */
    emit_u(0xffc00000u);  /* -qNaN */
    emit_u(0x7f800000u);  /* +Inf */
    emit_u(0xff800000u);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);  /* min negative subnormal: -2^-149 */
    emit_u(0x00400000u);  /* mid positive subnormal */
    emit_u(0x80400000u);  /* mid negative subnormal */
    emit_u(0x007fffffu);  /* max positive subnormal: just below FLT_MIN */
    emit_u(0x807fffffu);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (4) --- */
    emit(FLT_MIN);        /* smallest positive normal: 2^-126 = 0x00800000 */
    emit(-FLT_MIN);
    emit(FLT_MAX);        /* largest positive normal: 0x7f7fffff */
    emit(-FLT_MAX);

    /* --- Section 4: Near 1.0 ULP neighbors (6) --- */
    emit_u(0x3f7fffffu);  /* one ULP below 1.0: ~0.9999999404... */
    emit(1.0f);           /* 1.0 exactly: int=1, frac=0 */
    emit_u(0x3f800001u);  /* one ULP above 1.0: ~1.0000001192... */
    emit_u(0x3f7ffff0u);  /* a few ULPs below 1.0 */
    emit_u(0x3f800010u);  /* a few ULPs above 1.0 */
    emit(-1.0f);          /* -1.0: int=-1, frac=-0 */

    /* --- Section 5: Exponent boundary values (6) --- */
    emit(0.5f);           /* 0x3f000000: int=0, frac=0.5 */
    emit(-0.5f);
    emit(2.0f);           /* 0x40000000: int=2, frac=0 */
    emit(-2.0f);
    emit(4.0f);           /* 0x40800000: int=4, frac=0 */
    emit(-4.0f);

    /* --- Section 6: Half-integer values (14) --- */
    /* For n + 0.5, int part = n, frac = 0.5 */
    emit(1.5f);
    emit(-1.5f);
    emit(2.5f);
    emit(-2.5f);
    emit(3.5f);
    emit(-3.5f);
    emit(4.5f);
    emit(-4.5f);
    emit(5.5f);
    emit(-5.5f);
    emit(6.5f);
    emit(-6.5f);
    emit(7.5f);
    emit(-7.5f);

    /* --- Section 7: Large integers (no fractional part) (8) --- */
    /* float has 23-bit mantissa; integers >= 2^23 are exact */
    emit_u(0x4b000000u);  /* 2^23 = 8388608.0: exact integer, frac=0 */
    emit_u(0xcb000000u);  /* -2^23 */
    emit_u(0x4b800000u);  /* 2^24 = 16777216.0: exact integer, frac=0 */
    emit_u(0xcb800000u);  /* -2^24 */
    emit(1.0e7f);         /* 10000000.0: exact integer representation */
    emit(-1.0e7f);
    emit(1.0e10f);        /* large: no fractional part possible */
    emit(-1.0e10f);

    /* --- Section 8: ULP triplets around integer crossings (15) --- */
    /* At each integer n, test one ULP below, exact, one ULP above */
    emit_u(0x3fffffffu);  /* one ULP below 2.0 from below: ~1.9999999... */
    emit(2.0f);           /* 2.0 exactly: int=2, frac=0 */
    emit_u(0x40000001u);  /* one ULP above 2.0: ~2.0000002... */

    emit_u(0x40400000u);  /* 3.0 exactly: int=3, frac=0 */
    emit_u(0x403fffffu);  /* one ULP below 3.0: ~2.9999998... */
    emit_u(0x40400001u);  /* one ULP above 3.0: ~3.0000002... */

    emit_u(0x40800000u);  /* 4.0 exactly: int=4, frac=0 */
    emit_u(0x407fffffu);  /* one ULP below 4.0 */
    emit_u(0x40800001u);  /* one ULP above 4.0 */

    emit_u(0x41200000u);  /* 10.0 exactly: int=10, frac=0 */
    emit_u(0x411fffffu);  /* one ULP below 10.0 */
    emit_u(0x41200001u);  /* one ULP above 10.0 */

    emit_u(0x42c80000u);  /* 100.0 exactly: int=100, frac=0 */
    emit_u(0x42c7ffffu);  /* one ULP below 100.0 */
    emit_u(0x42c80001u);  /* one ULP above 100.0 */

    /* --- Section 9: Small fractional inputs (8) --- */
    /* All in [0,1): int part = 0, frac = x */
    emit(0.1f);
    emit(-0.1f);
    emit(0.25f);          /* exact in binary: frac = 0.25 */
    emit(-0.25f);
    emit(0.75f);          /* exact in binary: frac = 0.75 */
    emit(-0.75f);
    emit(0.99999994f);    /* just below 1.0 as float: frac ~ 1 */
    emit(-0.99999994f);

    /* --- Section 10: Mixed and boundary cases (26) --- */
    /* Pi-related values: non-trivial int/frac split */
    emit(3.14159265f);    /* pi: int=3, frac~0.14159 */
    emit(-3.14159265f);
    emit(6.28318530f);    /* 2*pi: int=6, frac~0.28318 */
    emit(-6.28318530f);

    /* e: int=2, frac~0.71828 */
    emit(2.71828182f);
    emit(-2.71828182f);

    /* Values near 0.5 fractional (halfway between integers) */
    emit(0.5f);           /* already in section 5, but placed here as -0.5 variant */
    emit(10.5f);          /* int=10, frac=0.5 */
    emit(-10.5f);
    emit(100.5f);         /* int=100, frac=0.5 */
    emit(-100.5f);

    /* Values with non-trivial fractional parts at various magnitudes */
    emit(1.1f);
    emit(-1.1f);
    emit(2.7f);
    emit(-2.7f);
    emit(9.9f);
    emit(-9.9f);
    emit(15.999f);        /* just below 16: int=15, frac~0.999 */
    emit(-15.999f);

    /* Very small normal values: int=0, frac=x */
    emit(1.0e-20f);
    emit(-1.0e-20f);

    /* ULP neighbors of 0.5 */
    emit_u(0x3effffffu);  /* one ULP below 0.5 */
    emit_u(0x3f000001u);  /* one ULP above 0.5 */

    /* Large values with fractional part still representable */
    emit_u(0x49800000u);  /* 2^20 = 1048576.0: exact integer, frac=0 */
    emit_u(0x4a000000u);  /* 2^21 = 2097152.0: exact integer, frac=0 */
}

/* ------------------------------------------------------------------ */
/* Dense sweeps (accuracy path only)                                   */
/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* Sample [0, 1) every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f800000u; /* 1.0 */
    for (uint32_t b = 0; b < end; b += 4194304)
        emit_u(b);
}

/* Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{
    float lo = -20.0f;
    float hi =  20.0f;
    int n = 300;
    for (int i = 0; i < n; i++) {
        float x = lo + (hi - lo) * (float)i / (float)(n - 1);
        emit(x);
    }
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
    test_exhaustive_small();
    test_random_300();
#endif
    return 0;
}

